        } else {
            binding.fabCart.setVisibility(View.VISIBLE);
            binding.bottomNavigation.setVisibility(View.VISIBLE);
            binding.bottomPanel.setVisibility(View.GONE);
            binding.fabCart.setOnClickListener(v -> handleCheckout());
